import { Component } from 'react';

class ErrorBoundary extends Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }

  componentDidCatch(error, errorInfo) {
    console.error('ErrorBoundary capturou:', error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        this.props.fallback || (
          <div className="p-4 bg-red-50 border border-red-200 rounded">
            <h2 className="text-red-800 font-bold">Algo deu errado</h2>
            <p className="text-red-600">{this.state.error?.message}</p>
          </div>
        )
      );
    }

    return this.props.children;
  }
}

function App() {
  return (
    <div>
      <h1>Minha App</h1>

      {/* Protege uma seção que pode falhar */}
      <ErrorBoundary fallback={<p>Erro ao carregar o dashboard</p>}>
        <Dashboard />
      </ErrorBoundary>

      {/* Outro boundary independente */}
      <ErrorBoundary fallback={<p>Erro na sidebar</p>}>
        <Sidebar />
      </ErrorBoundary>
    </div>
  );
}
